import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull partial sink case 2 fallthrough", () => {
  it("should correctly handle partial sink with 2 args where second arg is a sink object", () => {
    let index = 0
    const values = [1, 2, 3]
    const source = (end: any, cb: (end: any, data?: number) => void) => {
      if (end) return cb(end)
      if (index >= values.length) return cb(true)
      cb(null, values[index++])
    }

    const collected: number[] = []

    // A sink object (has sink and source properties)
    // sink consumes the stream, source emits nothing
    const collectSink = {
      sink: (read: (end: any, cb: (end: any, data?: number) => void) => void) => {
        const next = () => {
          read(null, (end: any, data?: number) => {
            if (end) return
