    // Create partial sink with a through function and a sink object
    // length === 2, so case 2 is triggered
    const partialSink = pull(
      (read: any) => (end: any, cb: any) => read(end, (e: any, d?: number) => {
        if (e) return cb(e)
        cb(null, d! * 2)
