    expect(typeof partialSink).toBe("function")

    // Apply partial sink to source
    // In original: pull(read, ref[0], ref[1]) - correct, sink consumes stream
    // In mutated: pull(read, ref[0], ref[1], undefined) - ref[2] is undefined
    // After sink object is processed, read = collectSink.source
    // Then undefined is processed: skipped (not function, not object)
    // Returns collectSink.source
    // This means the behavior differs: original returns collectSink.source, mutated also returns collectSink.source
    // Hmm, same result...

    // Let me try where ref[1] is a through that returns undefined
    // Actually let me just verify the collected values
    partialSink(source)

    expect(collected).toEqual([2, 4, 6])
  })
})
```

